+}
+
+func TestSectionResolver_AgentAppendIsAdditive(t *testing.T) {
+	dir := t.TempDir()
+	writeSection(t, dir, "tools.md", "base tools")
+	writeSection(t, dir, "tools.agent-implementer_append.md", "impl tips")
